1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = { op: "quote"; items: Item[] };
9	export type Damage = { itemType: string; amount: number };
10	export type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Damage[] } };
11	export type Step = QuoteStep | ClaimStep;
12	
13	export type Scenario = {
14	  customer: { yearsWithMHPCO: number };
15	  steps: Step[];
16	};
17	
18	export type QuoteResult = { premium: number };
19	export type ClaimResult = { payout: number; remainingCap: number };
20	export type StepResult = QuoteResult | ClaimResult;
21	export type ScenarioResult = { results: StepResult[] };
22	
23	const PROCESSING_FEE = 5;
24	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
25	
26	const BASE_PREMIUMS: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	  rune: 25,
32	  moonstone: 25,
33	};
34	
35	const INSURANCE_VALUES: Record<string, number> = {
36	  sword: 1000,
37	  amulet: 600,
38	  staff: 800,
39	  potion: 400,
40	  rune: 250,
41	  moonstone: 250,
42	};
43	
44	const DEDUCTIBLE = 100;
45	const CAP_MULTIPLIER = 2;
46	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
47	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
48	
49	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
50	const BLOCK_SIZE = 3;
51	const BLOCK_BASE_PREMIUM = 60;
52	
53	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
54	
55	const countBy = <T>(items: T[], keyOf: (item: T) => string): Record<string, number> => {
56	  const counts: Record<string, number> = {};
57	  for (const item of items) {
58	    const key = keyOf(item);
59	    counts[key] = (counts[key] ?? 0) + 1;
60	  }
61	  return counts;
62	};
63	
64	const countItemsByType = (items: Item[]): Record<string, number> =>
65	  countBy(items, (item) => item.type);
66	
67	const componentGroupPremium = (type: string, count: number): number =>
68	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];
69	
70	const itemsBasePremium = (items: Item[]): number => {
71	  const mainItems = items.filter((item) => !isComponent(item));
72	  const components = items.filter(isComponent);
73	  const mainTotal = mainItems.reduce(
74	    (sum, item) => sum + BASE_PREMIUMS[item.type],
75	    0,
76	  );
77	  const componentTotal = Object.entries(countItemsByType(components)).reduce(
78	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
79	    0,
80	  );
81	  return mainTotal + componentTotal;
82	};
83	
84	const CURSE_SURCHARGE_RATE = 0.5;
85	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
86	const HIGH_ENCHANTMENT_THRESHOLD = 5;
87	
88	const itemModifiersSurcharge = (item: Item): number => {
89	  const base = BASE_PREMIUMS[item.type];
90	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
91	  const highEnchantment = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
92	  return curse + highEnchantment;
93	};
94	
95	const sumItemModifiers = (items: Item[]): number =>
96	  items.reduce((sum, item) => sum + itemModifiersSurcharge(item), 0);
97	
98	const LOYALTY_DISCOUNT_RATE = 0.2;
99	const LOYALTY_YEARS_THRESHOLD = 2;
100	
101	const policyLevelAdjustments = (basePremium: number, yearsWithMHPCO: number): number => {
102	  const firstContract = basePremium * FIRST_CONTRACT_SURCHARGE_RATE;
103	  const loyalty = yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? -basePremium * LOYALTY_DISCOUNT_RATE : 0;
104	  return firstContract + loyalty;
105	};
106	
107	const quoteStep = (step: QuoteStep, yearsWithMHPCO: number): QuoteResult => {
108	  const basePremium = itemsBasePremium(step.items);
109	  const itemModifiers = sumItemModifiers(step.items);
110	  const policyAdjustments = policyLevelAdjustments(basePremium, yearsWithMHPCO);
111	  const premium = basePremium + itemModifiers + policyAdjustments + PROCESSING_FEE;
112	  return { premium: Math.ceil(premium) };
113	};
114	
115	type PolicyState = { items: Item[]; insuranceSum: number; remainingCap: number };
116	
117	const insuranceSum = (items: Item[]): number =>
118	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
119	
120	const isHighEnchantment = (item: Item | undefined): boolean =>
121	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
122	
123	const reimbursableAmount = (item: Item | undefined, amount: number): number =>
124	  isHighEnchantment(item) ? amount * HIGH_ENCHANTMENT_CLAIM_RATE : amount;
125	
126	const damagePayout = (damage: Damage, items: Item[]): number => {
127	  const item = items.find((i) => i.type === damage.itemType);
128	  return reimbursableAmount(item, damage.amount) - DEDUCTIBLE;
129	};
130	
131	const validateDamageCounts = (damages: Damage[], items: Item[]): void => {
132	  const itemCounts = countItemsByType(items);
133	  const damageCounts = countBy(damages, (dmg) => dmg.itemType);
134	  for (const [type, count] of Object.entries(damageCounts)) {
135	    if (count > (itemCounts[type] ?? 0)) throw new Error(`claim rejected: more damages of type ${type} than insured`);
136	  }
137	};
138	
139	const claimStep = (step: ClaimStep, policies: Map<number, PolicyState>): ClaimResult => {
140	  const policy = policies.get(step.policy)!;
141	  validateDamageCounts(step.incident.damages, policy.items);
142	  const desiredPayout = step.incident.damages.reduce(
143	    (sum, dmg) => sum + damagePayout(dmg, policy.items),
144	    0,
145	  );
146	  const payout = Math.min(desiredPayout, policy.remainingCap);
147	  policy.remainingCap -= payout;
148	  return { payout, remainingCap: policy.remainingCap };
149	};
150	
151	const newPolicyState = (items: Item[]): PolicyState => {
152	  const sum = insuranceSum(items);
153	  return { items, insuranceSum: sum, remainingCap: sum * CAP_MULTIPLIER };
154	};
155	
156	export const runScenario = (scenario: Scenario): ScenarioResult => {
157	  const policies = new Map<number, PolicyState>();
158	  const results: StepResult[] = [];
159	  scenario.steps.forEach((step, idx) => {
160	    if (step.op === "quote") {
161	      results.push(quoteStep(step, scenario.customer.yearsWithMHPCO));
162	      policies.set(idx, newPolicyState(step.items));
163	    } else {
164	      results.push(claimStep(step, policies));
165	    }
166	  });
167	  return { results };
168	};
